import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';

const root = ReactDOM.createRoot(document.getElementById('root'));
// Global handler to avoid noisy uncaught promise errors for optional browser extensions
window.addEventListener('unhandledrejection', (event) => {
	try {
		const reason = event.reason;
		// Detect typical MetaMask/inpage error messages
		if (reason && (String(reason).includes('MetaMask') || String(reason).includes('inpage'))) {
			// Prefer a gentle warning instead of an uncaught error in console
			console.warn('Optional extension error (MetaMask/inpage):', reason?.message || reason);
			// Prevent the browser from logging this as an uncaught promise in some environments
			if (typeof event.preventDefault === 'function') event.preventDefault();
		}
	} catch (e) {
		// fallback: do nothing
	}
});

root.render(<React.StrictMode><App /></React.StrictMode>);
